import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from './services/auth.service';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  private router = inject(Router);
  private auth = inject(AuthService);

  get isLoginRoute(): boolean {
    return this.router.url.startsWith('/login');
  }

  get isLoggedIn(): boolean {
    return this.auth.isLoggedIn();
  }

  get role(): 'admin' | 'employee' | null {
    return this.auth.role();
  }

  get username(): string | null {
    return this.auth.username();
  }

  get isAdmin(): boolean {
    return this.role === 'admin';
  }

  get isEmployee(): boolean {
    return this.role === 'employee';
  }

  logout(): void {
    this.auth.logout();
    this.router.navigateByUrl('/login');
  }
}
<header class="app-header" *ngIf="!isLoginRoute">
  <div class="brand">
    <div class="brand-mark">
      <img
        src="assets/logospa.png"
        alt="SPA &ndash; Pratiques Aluminium"
        class="brand-logo"
      />
    </div>

    <div>
      <div class="brand-title">SPA &mdash; Soci&eacute;t&eacute; d&rsquo;Aluminium</div>
      <div class="brand-subtitle">Facturation | Vente &amp; Fabrication</div>
    </div>
  </div>
  <nav class="nav" *ngIf="isLoggedIn">
    <a *ngIf="isAdmin" routerLink="/invoices" routerLinkActive="active">Factures</a>
    <a *ngIf="isAdmin" routerLink="/quotes" routerLinkActive="active">Devis</a>
    <a routerLink="/stock" routerLinkActive="active">Stock</a>
    <a *ngIf="isAdmin" routerLink="/stock/history" routerLinkActive="active">Historique Stock</a>
    <a *ngIf="isAdmin" routerLink="/estimation" routerLinkActive="active">Estimation</a>
    <a *ngIf="isAdmin" class="btn primary" routerLink="/invoices/new">Nouvelle facture</a>
    <div class="nav-meta">
      <span class="nav-user" *ngIf="username">
        Connect&eacute;: {{ username }} ({{ role }})
      </span>
      <button class="btn ghost" type="button" (click)="logout()">D&eacute;connexion</button>
    </div>
  </nav>
</header>

<main class="app-main">
  <router-outlet></router-outlet>
</main>

<footer class="app-footer" *ngIf="!isLoginRoute">
  SPA &mdash; Soci&eacute;t&eacute; d&rsquo;Aluminium &middot; Merci pour votre confiance
</footer>
